let raw = $input.first().json.output[0].content[0].text;

// Strip markdown fences just in case
raw = raw.replace(/^```json\s*/i, '').replace(/^```\s*/i, '').replace(/```\s*$/i, '').trim();

let data;
try {
  data = JSON.parse(raw);
} catch(e) {
  return [{ json: { formattedEmail: '<p>Error parsing response.</p>', fitScore: 'N/A', verdict: 'N/A' } }];
}

// Exact keys matching your OpenAI output
const fitScore = data["FitScore"] ?? 'N/A';
const strengths = Array.isArray(data["TopStrengths"]) ? data["TopStrengths"] : [];
const concerns = Array.isArray(data["KeyConcernsOrGaps"]) ? data["KeyConcernsOrGaps"] : [];
const verdict = data["FinalVerdict"] ?? 'N/A';
const summary = data["Summary"] ?? '';

const verdictFormatted = verdict === 'Hire'
  ? '✅ Hire'
  : verdict === 'Maybe'
  ? '⚠️ Maybe'
  : verdict === 'No Hire'
  ? '❌ No Hire'
  : verdict;

const strengthsHtml = strengths.length
  ? strengths.map(s => `<li style="margin-bottom:6px;">${s}</li>`).join('')
  : '<li>No strengths listed</li>';

const concernsHtml = concerns.length
  ? concerns.map(c => `<li style="margin-bottom:6px;">${c}</li>`).join('')
  : '<li>No concerns listed</li>';

const html = `
<div style="font-family: Arial, sans-serif; max-width: 600px; margin: auto; padding: 24px; border: 1px solid #e0e0e0; border-radius: 8px;">

  <h2 style="color: #2c3e50; margin-bottom: 20px;">Resume Analysis Result</h2>

  <div style="background: #f4f6f8; padding: 16px; border-radius: 6px; margin-bottom: 16px;">
    <h3 style="margin: 0 0 4px 0; color: #555; font-size: 14px; text-transform: uppercase;">Fit Score</h3>
    <p style="font-size: 32px; font-weight: bold; margin: 0; color: #2c3e50;">${fitScore} <span style="font-size: 16px; color: #888;">/ 10</span></p>
  </div>

  <div style="margin-bottom: 16px;">
    <h3 style="color: #27ae60; margin-bottom: 8px;">Top Strengths</h3>
    <ul style="line-height: 1.8; color: #333; padding-left: 20px;">${strengthsHtml}</ul>
  </div>

  <div style="margin-bottom: 16px;">
    <h3 style="color: #e67e22; margin-bottom: 8px;">Key Concerns</h3>
    <ul style="line-height: 1.8; color: #333; padding-left: 20px;">${concernsHtml}</ul>
  </div>

  <div style="background: #f4f6f8; padding: 16px; border-radius: 6px; margin-bottom: 16px;">
    <h3 style="margin: 0 0 8px 0; color: #555; font-size: 14px; text-transform: uppercase;">Final Verdict</h3>
    <p style="font-size: 22px; font-weight: bold; margin: 0;">${verdictFormatted}</p>
  </div>

  <div style="border-left: 4px solid #3498db; padding: 12px 16px; background: #f0f7ff; border-radius: 0 6px 6px 0;">
    <h3 style="margin: 0 0 6px 0; color: #3498db; font-size: 14px; text-transform: uppercase;">Summary</h3>
    <p style="margin: 0; line-height: 1.7; color: #444;">${summary}</p>
  </div>

</div>
`;

return [{ json: { formattedEmail: html, fitScore, verdict } }];
